function trimBytecodeMetadata(bytecode: string): string {
  // Bail on empty bytecode
  if (bytecode.length <= 4) {
    return bytecode;
  }

  // Gather length of CBOR metadata from the end of the file
  const rawLength = bytecode.slice(bytecode.length - 4);
  const metadataLength = parseInt(rawLength, 16) * 2;

  // Bail on unreasonable values for length
  if (metadataLength > bytecode.length - 4) {
    return bytecode;
  }

  // Gather what we assume is the CBOR encoded metadata, and try to parse it
  const metadataStart = bytecode.length - metadataLength - 4;
  const metadata = bytecode.slice(metadataStart, bytecode.length - 4);

  // Parse it to see if it is indeed valid metadata
  try {
    cbor.decode(Buffer.from(metadata, 'hex'));
  } catch (err) {
    // to do: log lack metadata to the user
    return bytecode;
  }

  // Return bytecode without it
  return bytecode.slice(0, metadataStart);
}

async function getBetterContractName(
  address: string,
  dependencies: TracerDependencies
): Promise<string | undefined> {
  // 1. See if nameTag exists already
  const nameTag = getFromNameTags(address, dependencies);
  if (nameTag) {
    return nameTag;
  }

  // 2. See if there is a name() method that gives string or bytes32
  dependencies.tracerEnv.enabled = false; // disable tracer to avoid tracing these calls
  const contractNameFromNameMethod = await fetchContractName(
    address,
    dependencies
  );
  dependencies.tracerEnv.enabled = true; // enable tracer back

  if (contractNameFromNameMethod) {
    dependencies.tracerEnv.nameTags[address] = contractNameFromNameMethod;
    return contractNameFromNameMethod;
  }

  // 3. Match bytecode
  const contractNameFromBytecodeComparison = await fetchContractNameUsingBytecodeComparison(
    address,
    dependencies
  );
  if (contractNameFromBytecodeComparison) {
    dependencies.tracerEnv.nameTags[
      address
    ] = contractNameFromBytecodeComparison;
    return contractNameFromBytecodeComparison;
  }
}

fallback() external payable {
    LibDiamond.DiamondStorage storage ds;
    bytes32 position = LibDiamond.DIAMOND_STORAGE_POSITION;
    // get diamond storage
    assembly {
        ds.slot := position
    }
    // get facet from function selector
    address facet = ds.selectorToFacetAndPosition[msg.sig].facetAddress;
    require(facet != address(0), "Diamond: Function does not exist");
    // Execute external function from facet using delegatecall and return any value.
    assembly {
        // copy function selector and any arguments
        calldatacopy(0, 0, calldatasize())
        // execute function call using the facet
        let result := delegatecall(gas(), facet, 0, calldatasize(), 0, 0)
        // get any return value
        returndatacopy(0, 0, returndatasize())
        // return any return value or error back to the caller
        switch result
            case 0 {
                revert(0, returndatasize())
            }
            default {
                return(0, returndatasize())
            }
    }
}

async function deployProxy(
    hre: HardhatRuntimeEnvironment,
    taskArgs: {
        contractName: string;
        constructorArgsParams: any[];
        constructorArgs?: string;
        initializer?: string;
        deploymentTypeImpl?: DeploymentType;
        deploymentTypeProxy?: DeploymentType;
        saltImpl?: string;
        saltProxy?: string;
        initialOwner?: string;
        noCompile?: boolean;
    },
): Promise<Contract> {
    if (!taskArgs.noCompile) {
        await hre.run(TASK_COMPILE);
    }

    const constructorArguments: any[] = await getConstructorArguments(
        taskArgs.constructorArgsParams,
        taskArgs.constructorArgs,
    );

    const wallet = await getWallet(hre);
    const deployer = new Deployer(hre, wallet);

    const contract = await deployer.loadArtifact(taskArgs.contractName);

    const proxy = await hre.upgrades.deployProxy(wallet, contract, constructorArguments, {
        deploymentTypeImpl: taskArgs.deploymentTypeImpl,
        saltImpl: taskArgs.saltImpl,
        deploymentTypeProxy: taskArgs.deploymentTypeProxy,
        saltProxy: taskArgs.saltProxy,
        initializer: taskArgs.initializer,
        initialOwner: taskArgs.initialOwner,
    });

    await proxy.waitForDeployment();

    return proxy;
}

public resolveActions(
  serverState: ServerState,
  diagnostic: Diagnostic,
  context: ResolveActionsContext
): CodeAction[] {
  const missingContractIdentifiers = this.parseContractIdentifiersFromMessage(
    diagnostic.message
  );

  const multiOverride = new Multioverride(missingContractIdentifiers);

  // When no specifier is present, solc sourceLocation covers the whole function body
  // so we can apply the general quickfix for specifiers
  const insertSpecifierQuickfix = resolveInsertSpecifierQuickFix(
    multiOverride,
    diagnostic,
    context,
    serverState.logger
  );

  if (insertSpecifierQuickfix.length > 0) {
    return insertSpecifierQuickfix;
  }

  // If just 'override' or 'override(A)' is present, assuming there are more
  // contracts that need to be specified besides A, solc error sourceLocation only
  // covers the `override(...)` string
  const updateSpecifierQuickfix = this._tryUpdateOverride(
    context,
    diagnostic,
    multiOverride
  );

  if (updateSpecifierQuickfix.length > 0) {
    return updateSpecifierQuickfix;
  }

  return [];
}

function signatureHelp(
  document: TextDocument,
  vsCodePosition: VSCodePosition,
  documentAnalyzer: ISolFileEntry,
  logger: Logger
): SignatureHelp | undefined {
  if (documentAnalyzer.text === undefined) {
    return undefined;
  }

  const analyzerTree = documentAnalyzer.analyzerTree.tree;

  const declarationSignature = getDeclarationSignature(
    vsCodePosition,
    document
  );

  if (!declarationSignature) {
    return undefined;
  }

  const definitionNode = documentAnalyzer.searcher.findDefinitionNodeByPosition(
    documentAnalyzer.uri,
    declarationSignature.declarationNodePosition,
    analyzerTree
  );

  if (!definitionNode) {
    return undefined;
  }

  const definitionSignature = getDefinitionSignature(definitionNode, logger);

  if (!definitionSignature) {
    return undefined;
  }

  return {
    signatures: [definitionSignature],
    activeSignature: undefined,
    activeParameter: declarationSignature.activeParameter,
  };
}

function shouldUpdateDependency(
  workspaceVersion: string | undefined,
  templateVersion: string,
): boolean {
  // We should not update the dependency if it is not yet installed in the workspace.
  if (workspaceVersion === undefined) {
    return false;
  }
  // NOTE: a specific version also a valid range that includes itself only
  const workspaceRange = semver.validRange(workspaceVersion, {
    includePrerelease: true,
  });
  const templateRange = semver.validRange(templateVersion, {
    includePrerelease: true,
  });
  assertHardhatInvariant(
    templateRange !== null,
    "All dependencies of the template should have valid versions",
  );
  // We should update the dependency if the workspace version could not be parsed.
  if (workspaceRange === null) {
    return true;
  }
  // We should update the dependency if the workspace range (or, in particular, a specific version) is not
  // a strict subset of the template range/does not equal the template version.
  return !semver.subset(workspaceRange, templateRange, {
    includePrerelease: true,
  });
}

