      // params
      .addOptionalParam("opcodes", "specify more opcodes to include in trace")
      .addOptionalParam("print", "specify print mode: console or json")

      // alias
      .addFlag("traceError", "enable tracer with verbosity 1")
      .addFlag("fulltraceError", "enable tracer with verbosity 2")
      .addFlag("fullTraceError", "enable tracer with verbosity 2")
      .addFlag("trace", "enable tracer with verbosity 3")
      .addFlag("fulltrace", "enable tracer with verbosity 4")
      .addFlag("fullTrace", "enable tracer with verbosity 4")
  );
}

async function replayStrategy(
  executionState:
    | DeploymentExecutionState
    | CallExecutionState
    | SendDataExecutionState
    | StaticCallExecutionState,
  strategy: ExecutionStrategy
): Promise<
  | DeploymentStrategyGenerator
  | CallStrategyGenerator
  | SendDataStrategyGenerator
  | StaticCallStrategyGenerator
> {
  switch (executionState.type) {
    case ExecutionSateType.DEPLOYMENT_EXECUTION_STATE:
      return replayExecutionStartegyWithOnchainInteractions(
        executionState,
        strategy
      );
    case ExecutionSateType.CALL_EXECUTION_STATE:
      return replayExecutionStartegyWithOnchainInteractions(
        executionState,
        strategy
      );
    case ExecutionSateType.SEND_DATA_EXECUTION_STATE:
      return replayExecutionStartegyWithOnchainInteractions(
        executionState,
        strategy
      );
    case ExecutionSateType.STATIC_CALL_EXECUTION_STATE:
      return replayStaticCallExecutionStrategy(executionState, strategy);
  }
}

async function replayStrategy(
  executionState:
    | DeploymentExecutionState
    | CallExecutionState
    | SendDataExecutionState
    | StaticCallExecutionState,
  strategy: ExecutionStrategy,
): Promise<
  | DeploymentStrategyGenerator
  | CallStrategyGenerator
  | SendDataStrategyGenerator
  | StaticCallStrategyGenerator
> {
  switch (executionState.type) {
    case ExecutionSateType.DEPLOYMENT_EXECUTION_STATE:
      return await replayExecutionStrategyWithOnchainInteractions(
        executionState,
        strategy,
      );
    case ExecutionSateType.CALL_EXECUTION_STATE:
      return await replayExecutionStrategyWithOnchainInteractions(
        executionState,
        strategy,
      );
    case ExecutionSateType.SEND_DATA_EXECUTION_STATE:
      return await replayExecutionStrategyWithOnchainInteractions(
        executionState,
        strategy,
      );
    case ExecutionSateType.STATIC_CALL_EXECUTION_STATE:
      return await replayStaticCallExecutionStrategy(executionState, strategy);
  }
}

public async accept(
  find: FinderType,
  orphanNodes: Node[],
  parent?: Node,
  expression?: Node
): Promise<Node> {
  this.setExpressionNode(expression);

  // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
  if (this.astNode.condition) {
    await (
      await find(
        this.astNode.condition,
        this.uri,
        this.rootPath,
        this.solFileIndex
      )
    ).accept(find, orphanNodes, parent);
  }

  // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
  if (this.astNode.trueExpression) {
    await (
      await find(
        this.astNode.trueExpression,
        this.uri,
        this.rootPath,
        this.solFileIndex
      )
    ).accept(find, orphanNodes, parent);
  }

  // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
  if (this.astNode.falseExpression) {
    await (
      await find(
        this.astNode.falseExpression,
        this.uri,
        this.rootPath,
        this.solFileIndex
      )
    ).accept(find, orphanNodes, parent);
  }

  return this;
}

async function handleCommonErrors<T>(promise: Promise<T>): Promise<T> {
    try {
        return await promise;
    } catch (error) {
        if (error instanceof DockerNotRunningError || error instanceof DockerBadGatewayError) {
            throw new ZkSyncSolcPluginError(
                'Docker Desktop is not running.\nPlease open it and wait until it finishes booting.',
                error,
            );
        }

        if (error instanceof DockerHubConnectionError) {
            throw new ZkSyncSolcPluginError(
                'Error connecting to Docker Hub.\nPlease check your internet connection.',
                error,
            );
        }

        if (error instanceof DockerServerError) {
            throw new ZkSyncSolcPluginError('Docker error', error);
        }

        if (error instanceof ImageDoesntExistError) {
            throw new ZkSyncSolcPluginError(
                `Docker image ${HardhatDocker.imageToRepoTag(error.image)} doesn't exist.\n` +
                    'Make sure you chose a valid zksolc version.',
            );
        }

        throw error;
    }
}

